1947     if (!Cached) {
1948       Cached = Builder.CreateAlloca(Storage->getType(), 0, nullptr,
1949                                     Storage->getName() + ".debug");
1950       Builder.CreateStore(Storage, Cached);
1951     }
1952     Storage = Cached;
1953     // FIXME: LLVM lacks nuanced semantics to differentiate between
1954     // memory and direct locations at the IR level. The backend will
1955     // turn a dbg.declare(alloca, ..., DIExpression()) into a memory
1956     // location. Thus, if there are deref and offset operations in the
1957     // expression, we need to add a DW_OP_deref at the *start* of the
1958     // expression to first load the contents of the alloca before
1959     // adjusting it with the expression.
1960     Expr = DIExpression::prepend(Expr, DIExpression::DerefBefore);
1961   }
1962 
1963   Expr = Expr->foldConstantMath();
1964   return {{*Storage, *Expr}};
